                        {part.status === 'InTransit' && <Truck size={14} />}
                        {part.status === 'Received' && <PackageCheck size={14} />}
                        {part.status === 'Installed' && <CheckCircle size={14} />}
                        {part.status}
                      </span>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      )}

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center p-4 z-50">
